mapper.select:
select wr.id, wr.withdrawal_code, m.nickname as artist_name, wr.requested_amount, wr.net_amount, wr.bank_name, to_char(wr.requested_at, 'MM.DD') as requested_at, coalesce(( select sum(s.net_amount) from tbl_settlement s where s.member_id = wr.member_id and s.status = 'PAID' ), 0) - coalesce(( select sum(wr2.net_amount) from tbl_withdrawal_request wr2 where wr2.member_id = wr.member_id and wr2.status in ('APPROVED', 'PAID') ), 0) as remaining_balance, wr.status from tbl_withdrawal_request wr join tbl_member m on wr.member_id = m.id
and ( m.nickname ilike '%' || #{keyword} || '%' or wr.withdrawal_code ilike '%' || #{keyword} || '%' )
and wr.status = #{status}
order by wr.id desc limit #{size} offset #{offset}

select count(*) from tbl_withdrawal_request wr join tbl_member m on wr.member_id = m.id
and ( m.nickname ilike '%' || #{keyword} || '%' or wr.withdrawal_code ilike '%' || #{keyword} || '%' )
and wr.status = #{status}
